import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;
import java.net.ConnectException;

@Service
public class SwiggyDeliveryService {
    private final DeliveryClient client;
    SwiggyDeliveryService(DeliveryClient c) { client = c; }

    @Retry(name = "delivery-api", fallbackMethod = "defaultEstimate")
    public int estimateDelivery(String orderId) throws ConnectException {
        return client.estimate(orderId);
    }

    private int defaultEstimate(String orderId, Exception e) {
        System.out.println("[Retry exhausted] Using default estimate for " + orderId);
        return 45;  // 45 minute default
    }

    // ConnectException: RETRY — delivery API server is temporarily unreachable
    // OrderNotFoundException: DON'T RETRY — order doesn't exist, retry won't help

    interface DeliveryClient { int estimate(String id) throws ConnectException; }
}

