import io.github.resilience4j.ratelimiter.annotation.RateLimiter;
import io.github.resilience4j.ratelimiter.RequestNotPermittedException;
import org.springframework.stereotype.Service;

@Service
public class ZerodhaNseService {
    private final NseClient client;
    ZerodhaNseService(NseClient c) { client = c; }

    @RateLimiter(name = "nse-api", fallbackMethod = "orderThrottled")
    public OrderAck submitOrder(Order order) {
        return client.submit(order);
    }

    private OrderAck orderThrottled(Order order, RequestNotPermittedException e) {
        // Caller can retry after the rate limit window refreshes:
        System.out.println("[Rate limit] NSE API quota exceeded — throttling order");
        throw new OrderThrottledException("Rate limit exceeded — retry in 1s");
    }

    // PROTECTION:
    // Without @RateLimiter: Zerodha's 500 order threads all hit NSE
    // → NSE rate-limits Zerodha's IP → all orders blocked
    // With @RateLimiter: Zerodha self-throttles to 200/s
    // → NSE sees clean traffic → no IP block

    interface NseClient { OrderAck submit(Order o); }
    record Order(String id) {}
    record OrderAck(String orderId, String status) {}
    static class OrderThrottledException extends RuntimeException {
        OrderThrottledException(String m) { super(m); }
    }
}

