        // Mock: fail twice, succeed third:
        when(client.estimate(anyString()))
            .thenThrow(new java.net.ConnectException("blip"))
            .thenThrow(new java.net.ConnectException("blip"))
            .thenReturn(30);  // 30 minute estimate on 3rd attempt

