import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;

@Service
public class VisaGatewayService {
    private final VisaClient client;
    VisaGatewayService(VisaClient c) { client = c; }

    // @CircuitBreaker OUTER wraps the ENTIRE retry sequence:
    @CircuitBreaker(name = "visa", fallbackMethod = "visaCBFallback")
    @Retry(name = "visa")  // ← INNER: retries happen inside the CB
    public PaymentResult charge(ChargeRequest req) {
        return client.charge(req);
    }

    private PaymentResult visaCBFallback(ChargeRequest req, Exception e) {
        System.out.println("[CB Fallback] Visa gateway unavailable");
        return PaymentResult.queued(req.getId());
    }

    // WHY CB COUNTS 1 (not 3):
    // @Retry executes: attempt 1 → attempt 2 → attempt 3 (all fail)
    // Only after ALL retries fail does the exception propagate up
    // @CircuitBreaker (outer) sees: ONE call, ONE failure
    // CB records 1 failure per retry sequence
    //
    // WRONG ORDER (Retry outside CB):
    // @Retry executes attempt 1 → CB records failure
    //                attempt 2 → CB records failure
    //                attempt 3 → CB records failure
    // CB records 3 failures per retry sequence → opens 3× faster!

    interface VisaClient { PaymentResult charge(ChargeRequest r); }
    record ChargeRequest(String id, double amount) { String getId(){return id;} }
    record PaymentResult(String id, String status) {
        static PaymentResult queued(String id) { return new PaymentResult(id, "QUEUED"); }
    }
}

