import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;

@Service
public class FlipkartInventoryService {
    private final InventoryClient client;
    FlipkartInventoryService(InventoryClient c) { client = c; }

    @Retry(name = "inventory-api", fallbackMethod = "stockUnknown")
    public int checkStock(String productId) {
        return client.getStock(productId);
    }

    private int stockUnknown(String productId, Exception e) {
        System.out.println("[Retry exhausted] Stock unknown for " + productId);
        return -1;  // -1 signals 'stock unknown' to UI → show 'Check availability'
    }

    // WHY JITTER MATTERS:
    // Without jitter: 1000 threads fail → all retry at exactly 200ms
    //   → 1000 requests hit inventory server at T=200ms → new spike → all fail again
    // With jitter: each thread picks random delay in [100ms, 300ms]
    //   → retries spread across 200ms window → smooth load on server

    interface InventoryClient { int getStock(String id); }
}

