import java.util.*;

@Service
public class SwiggyAnalyticsService {
    private static final int QUEUE_CAPACITY = 1000;
    private final BlockingQueue<AnalyticsEvent> overflow = new LinkedBlockingQueue<>(QUEUE_CAPACITY);
    private final AnalyticsClient client;

    SwiggyAnalyticsService(AnalyticsClient c) { client = c; }

    // app.yml: ratelimiter.instances.swiggy-analytics:
    //   limitForPeriod: 50, limitRefreshPeriod: 1s, timeoutDuration: 0ms
    @RateLimiter(name = "swiggy-analytics", fallbackMethod = "queueEvent")
    public void recordEvent(AnalyticsEvent event) {
        client.send(event);  // direct send if within rate
    }

    private void queueEvent(AnalyticsEvent event, RequestNotPermittedException e) {
        boolean added = overflow.offer(event);
        if (!added) System.err.println("[Analytics] Queue full — dropping event: " + event.id());
    }

    @Scheduled(fixedRate = 1000)  // drain queue every second
    public void drainQueue() {
        List<AnalyticsEvent> batch = new ArrayList<>();
        overflow.drainTo(batch, 50);  // drain up to 50 per second
        batch.forEach(e -> {
            try { client.send(e); } catch (Exception ex) { overflow.offer(e); }
        });
        if (!batch.isEmpty())
            System.out.printf("[Analytics] Drained %d queued events%n", batch.size());
    }

    interface AnalyticsClient { void send(AnalyticsEvent e); }
    record AnalyticsEvent(String id, String type) {}
}

