import io.github.resilience4j.ratelimiter.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import jakarta.annotation.PostConstruct;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class RateLimiterMonitor {
    private final RateLimiterRegistry registry;
    private final AtomicLong totalCalls    = new AtomicLong(0);
    private final AtomicLong rejectedCalls = new AtomicLong(0);

    RateLimiterMonitor(RateLimiterRegistry r) { registry = r; }

    @PostConstruct
    public void listen() {
        registry.getAllRateLimiters().forEach(rl -> {
            rl.getEventPublisher()
                .onSuccess(e -> totalCalls.incrementAndGet())
                .onFailure(e -> {
                    totalCalls.incrementAndGet();
                    rejectedCalls.incrementAndGet();
                });
        });
    }

    @Scheduled(fixedRate = 60_000)
    public void reportMetrics() {
        long total    = totalCalls.getAndSet(0);
        long rejected = rejectedCalls.getAndSet(0);
        if (total == 0) return;

        double rejectionRate = 100.0 * rejected / total;
        System.out.printf("[RateLimiter] calls=%d rejected=%d rate=%.1f%%%n",
            total, rejected, rejectionRate);

        if (rejectionRate > 10) {
            System.err.printf("[ALERT] Rate limit rejection rate %.1f%% > 10%%%n" +
                "Consider increasing limitForPeriod%n", rejectionRate);
        }
    }
}

