import io.github.resilience4j.ratelimiter.RequestNotPermittedException;
import org.springframework.stereotype.Service;

@Service
public class ZerodhaOrderSubmissionService {
    private final NseClient client;
    ZerodhaOrderSubmissionService(NseClient c) { client = c; }

    // Layer 1 (OUTERMOST): RateLimiter — controls call frequency
    @RateLimiter(name = "nse", fallbackMethod = "rateLimitedOrder")
    // Layer 2: CircuitBreaker — stops calls when NSE is struggling
    @CircuitBreaker(name = "nse", fallbackMethod = "circuitOpenOrder")
    // Layer 3 (INNERMOST): Retry — handles transient connection failures
    @Retry(name = "nse")
    public OrderAck submitOrder(Order order) {
        return client.submit(order);
    }

    // Fallback for @RateLimiter (called when quota exceeded):
    private OrderAck rateLimitedOrder(Order o, RequestNotPermittedException e) {
        System.out.println("[RL] Rate limit exceeded — queuing order");
        return OrderAck.of(o.id(), "QUEUED_RATE_LIMIT");
    }

    // Fallback for @CircuitBreaker (called when NSE circuit is OPEN):
    private OrderAck circuitOpenOrder(Order o, Exception e) {
        System.out.println("[CB] NSE circuit open — queuing order");
        return OrderAck.of(o.id(), "QUEUED_NSE_DOWN");
    }

    // No separate @Retry fallback: @CircuitBreaker's fallback handles retry exhaustion too

    // WHAT EACH LAYER HANDLES:
    // @RateLimiter (outer): 'Am I calling too fast?' → queue/drop excess calls
    // @CircuitBreaker (mid): 'Is NSE struggling?' → fast-fail to fallback
    // @Retry (inner): 'Was this a transient blip?' → retry automatically

    interface NseClient { OrderAck submit(Order o); }
    record Order(String id) { String id(){return id;} }
    record OrderAck(String orderId, String status) {
        static OrderAck of(String id, String s){return new OrderAck(id,s);}
    }
}

import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class IdempotentChargeService {
    private final VisaClient client;
    // Cache results by idempotency key:
    private final Map<String,ChargeResult> resultCache = new ConcurrentHashMap<>();

    IdempotentChargeService(VisaClient c) { client = c; }

    @Retry(name = "idempotent-charge", fallbackMethod = "chargeFailed")
    public ChargeResult chargeWithRetry(String idempotencyKey, ChargeRequest req) {
        // Check if already processed (idempotency hit):
        ChargeResult cached = resultCache.get(idempotencyKey);
        if (cached != null) {
            System.out.println("[Idempotency] Returning cached result for " + idempotencyKey);
            return cached;
        }

        // Always pass the same idempotency key to Visa:
        ChargeResult result = client.charge(idempotencyKey, req);
        resultCache.put(idempotencyKey, result);
        return result;
    }

    private ChargeResult chargeFailed(String iKey, ChargeRequest req, Exception e) {
        return ChargeResult.failed(iKey, e.getMessage());
    }

    // Idempotency + retry interaction:
    // Attempt 1: IOException → retry
    // Attempt 2: Visa returns result (possibly 'already_processed')
    //            → cached in resultCache → safe return
    // Even if attempt 1 was partially processed, idempotency key prevents double charge

    interface VisaClient { ChargeResult charge(String iKey, ChargeRequest r); }
    record ChargeRequest(double amount) {}
    record ChargeResult(String id, String status) {
        static ChargeResult failed(String id, String reason) {
            return new ChargeResult(id, "FAILED:" + reason);
        }
    }
}

