import java.util.concurrent.atomic.*;

@Service
class ZResilient{
    interface NseClient{String submit(String id);}
    private final NseClient c;
    ZResilient(NseClient c){this.c=c;}
    @RateLimiter(name="z",fallbackMethod="rlFb")
    @CircuitBreaker(name="z",fallbackMethod="cbFb")
    @Retry(name="z")
    public String submit(String id){return c.submit(id);}
    private String rlFb(String id, RequestNotPermittedException e){return "RATE_LIMITED";}
    private String cbFb(String id, Exception e){return "CB_OPEN";}
}

@Service
class ZMonitor{
    public final AtomicInteger rlRejected=new AtomicInteger(0);
    public final AtomicInteger cbOpened=new AtomicInteger(0);
    private final CircuitBreakerRegistry cbReg;
    private final RateLimiterRegistry rlReg;
    ZMonitor(CircuitBreakerRegistry cb,RateLimiterRegistry rl){cbReg=cb;rlReg=rl;}
    @PostConstruct void listen(){
        cbReg.getAllCircuitBreakers().forEach(cb->cb.getEventPublisher()
            .onStateTransition(e->{
                if(e.getStateTransition()==io.github.resilience4j.circuitbreaker.CircuitBreaker.StateTransition.CLOSED_TO_OPEN)
                    cbOpened.incrementAndGet();
            }));
        rlReg.getAllRateLimiters().forEach(rl->rl.getEventPublisher()
            .onFailure(e->rlRejected.incrementAndGet()));
    }
}

@SpringBootTest
class ZResilienceTest{
    @Autowired ZResilient svc;
    @Autowired ZMonitor mon;
    @MockBean ZResilient.NseClient client;
    @Autowired CircuitBreakerRegistry cbReg;
    @Autowired RateLimiterRegistry rlReg;
    @BeforeEach void reset(){
        cbReg.circuitBreaker("z").reset();
        mon.cbOpened.set(0); mon.rlRejected.set(0);
    }
    @Test void retrySucceedsOnThird(){
        when(client.submit(any()))
            .thenThrow(new RuntimeException("blip"))
            .thenThrow(new RuntimeException("blip"))
            .thenReturn("ACCEPTED");
        assertEquals("ACCEPTED",svc.submit("ORD-1"));
        verify(client,times(3)).submit(any());
    }
    @Test void cbOpens_afterFailures(){
        when(client.submit(any())).thenThrow(new RuntimeException("down"));
        for(int i=0;i<10;i++) svc.submit("ORD-"+i);
        assertTrue(cbReg.circuitBreaker("z").getState()==
            io.github.resilience4j.circuitbreaker.CircuitBreaker.State.OPEN||
            mon.cbOpened.get()>0,"CB should have opened");
    }
    @Test void fallback_returnsExpectedStatus(){
        when(client.submit(any())).thenThrow(new RuntimeException("down"));
        String result=svc.submit("ORD-X");
        assertTrue(result.equals("CB_OPEN")||result.equals("RATE_LIMITED"),
            "Should return fallback status");
    }
}
